        params: const <String, Object>{
          'iterations': 222,
          'bailout': 4.5,
          'colorScheme': 2,
        },
        visitedAt: DateTime.utc(2024),
      );

      provider.applyToController(entry, controller);

      expect(controller.module.id, 'julia');
      expect(controller.params['iterations'], 222);
      expect(controller.params['bailout'], closeTo(4.5, 1e-12));
      expect(controller.params['colorScheme'], 2);
      expect(controller.view.pan, Vector2(0.25, -0.5));
      expect(controller.view.zoom, 2.5);
      expect(controller.view.rotation, Vector3(0.1, 0.2, 0.3));
    });

    testWidgets('history replay keeps legacy structural controllers working',
        (tester) async {
      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      final controller = _LegacyReplayController();
      final entry = HistoryEntry(
        id: 'legacy-replay',
        moduleId: 'mandelbrot',
        view: FractalViewState(
          pan: Vector2(-0.25, 0.5),
          zoom: 3.5,
          rotation: Vector3(0.4, 0.5, 0.6),
        ),
        params: const <String, Object>{'iterations': 180},
        visitedAt: DateTime.utc(2024),
      );

      provider.applyToController(entry, controller);

      expect(controller.params, {'iterations': 180});
      expect(controller.zoom, 3.5);
      expect(controller.pan, Vector2(-0.25, 0.5));
      expect(controller.rotation, Vector3(0.4, 0.5, 0.6));
    });
  });
}

import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';

/// Stable catalog entry used by the redesigned browser.
///
/// This is intentionally separate from [FractalModule] so we can scale the
/// catalog to many entries (e.g. PRD 200) while still mapping to currently
/// implemented render modules.
@immutable
class CatalogEntry {
  /// Stable ID for catalog persistence, analytics, and deep links.
  ///
  /// Must never change once published.
  final String catalogId;

  /// Backing runtime fractal module that can render this entry today.
  final FractalModule module;

  /// Display category used to group entries in the catalog UI.
  final String category;

  /// Optional search aliases used by catalog filtering.
  final List<String> aliases;

  const CatalogEntry({
    required this.catalogId,
    required this.module,
    required this.category,
    this.aliases = const [],
  });
}

import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/core/modules/builders/escape_time/catalog.dart';
import 'package:flutter_fractals/core/modules/builders/raymarched_3d/catalog.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/features/catalog/catalog_entry.dart';

/// Catalog data source for the Explore screen.
///
/// Phase 1: derives entries from currently implemented modules while assigning
/// stable catalog IDs. This keeps IDs future-proof for PRD-200 ingest.
class CatalogRepository {
  final List<CatalogEntry> entries;

  const CatalogRepository({required this.entries});

  factory CatalogRepository.fromRegistry(ModuleRegistry registry) {
    final categoriesById = {
      for (final config in escapeTimeCatalog) config.id: config.category,
      for (final config in raymarched3DCatalog) config.id: config.category,
    };

    return CatalogRepository(
      entries: registry.modules
          .map(
            (module) => CatalogEntry(
              // Stable prefix to decouple future module refactors from IDs.
              catalogId: 'core.${module.id}',
              module: module,
              category: categoriesById[module.id] ??
                  (module.dimension == FractalDimension.threeD
                      ? '3D Fractals'
                      : 'Other'),
            ),
          )
          .toList(growable: false),
    );
  }

  CatalogEntry byCatalogId(String catalogId) {
    return entries.firstWhere((entry) => entry.catalogId == catalogId);
  }

  @visibleForTesting
  Set<String> allIds() => entries.map((e) => e.catalogId).toSet();
}

import 'dart:async';

/// Cancelable debounce contract for catalog search input.
///
/// A search edit should publish only after [delay] has elapsed without a newer
/// edit. Keeping this behavior behind a small helper makes the timing contract
/// testable instead of relying on stacked [Future.delayed] callbacks.
final class CatalogSearchDebouncer {
  final Duration delay;
  Timer? _timer;

  CatalogSearchDebouncer({
    this.delay = const Duration(milliseconds: 300),
  });

  void schedule(void Function() callback) {
    _timer?.cancel();
    _timer = Timer(delay, callback);
  }

  void cancel() {
    _timer?.cancel();
    _timer = null;
  }

  void dispose() {
    cancel();
  }
}

