import 'package:flutter_fractals/features/catalog/catalog_search_debouncer.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('CatalogSearchDebouncer', () {
    test('only fires the latest scheduled callback', () async {
      final fired = <String>[];
      final debouncer = CatalogSearchDebouncer(
        delay: const Duration(milliseconds: 20),
      );
      addTearDown(debouncer.dispose);

      debouncer.schedule(() => fired.add('first'));
      await Future<void>.delayed(const Duration(milliseconds: 10));
      debouncer.schedule(() => fired.add('second'));

      await Future<void>.delayed(const Duration(milliseconds: 15));
      expect(fired, isEmpty);

      await Future<void>.delayed(const Duration(milliseconds: 20));
      expect(fired, ['second']);
    });

    test('cancel drops a pending callback', () async {
      var fired = false;
      final debouncer = CatalogSearchDebouncer(
        delay: const Duration(milliseconds: 20),
      );
      addTearDown(debouncer.dispose);

      debouncer.schedule(() => fired = true);
      debouncer.cancel();
      await Future<void>.delayed(const Duration(milliseconds: 30));

      expect(fired, isFalse);
    });
  });
}

import 'package:flutter_fractals/features/formulas/frm/complex.dart';
import 'package:flutter_fractals/features/formulas/frm/frm_ast.dart';
import 'package:flutter_fractals/features/formulas/frm/frm_parser.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('FrmParser (subset)', () {
    test('parses multiple formulas with init/iter sections', () {
      const src = r'''
; comment
Mandelbrot {
  z = (0,0)
  c = pixel
:
  z = z*z + c
}

Julia {
  z = pixel
  c = (0.285, 0.01)
:
  z = z*z + c
}
''';

      final file = FrmParser(src).parseFile();
      expect(
          file.formulas.map((f) => f.name).toList(), ['Mandelbrot', 'Julia']);
      expect(file.formulas[0].init.length, 2);
      expect(file.formulas[0].iter.length, 1);
    });

    test('rejects adjacent assignments without a newline separator', () {
      const src = r'''
Test {
  z = (0,0) c = pixel
:
  z = z*z + c
}
''';

      expect(
        () => FrmParser(src).parseFile(),
        throwsA(
          isA<FormatException>().having(
            (e) => e.message,
            'message',
            'Expected newline after statement',
          ),
        ),
      );
    });

    test('reports unterminated body when EOF appears before section separator',
        () {
      const src = r'''
Test {
  z = (0,0)
''';

      expect(
        () => FrmParser(src).parseFile(),
        throwsA(
          isA<FormatException>().having(
            (e) => e.message,
            'message',
            'Unterminated formula body',
          ),
        ),
      );
    });

    test('rejects complex-valued components inside complex literals', () {
      const src = r'''
Test {
  z = ((1,2), 3)
:
  z = z
}
''';

      final formula = FrmParser(src).parseFile().formulas.single;
      final ctx = FrmEvalContext(vars: {'pixel': const Complex(0, 0)});

      expect(
        () => formula.init.single.run(ctx),
        throwsA(
          isA<StateError>().having(
            (e) => e.message,
            'message',
            contains(
                'Complex literal components must evaluate to real scalars'),
          ),
        ),
      );
    });

    test('evaluates a simple iter statement', () {
      const src = r'''
Test {
  z = (0,0)
  c = (1,0)
:
  z = z*z + c
}
''';

      final formula = FrmParser(src).parseFile().formulas.single;
      final ctx = FrmEvalContext(vars: {
        'z': const Complex(0, 0),
        'c': const Complex(1, 0),
        'pixel': const Complex(0, 0),
      });

      for (final s in formula.init) {
        s.run(ctx);
      }
      // z=(0,0), c=(1,0)
      expect(ctx.vars['z']!.re, 0);
      expect(ctx.vars['c']!.re, 1);

      for (final s in formula.iter) {
        s.run(ctx);
      }
      // z = 0*0 + 1
      expect(ctx.vars['z']!.re, closeTo(1, 1e-12));
      expect(ctx.vars['z']!.im, closeTo(0, 1e-12));
    });

    test('returns immutable parse result lists', () {
      const src = r'''
Test {
  z = (0,0)
:
  z = z*z
}
''';

      final file = FrmParser(src).parseFile();
      final formula = file.formulas.single;

      expect(
        () => file.formulas.add(
          FrmFormula(name: 'Other', init: const [], iter: const []),
        ),
        throwsUnsupportedError,
      );
      expect(
        () => formula.init.add(const FrmAssign('c', FrmVar('pixel'))),
        throwsUnsupportedError,
      );
      expect(
        () => formula.iter.clear(),
        throwsUnsupportedError,
      );
    });
  });
}

// A small lexer for a restricted Fractint-like .frm subset.
//
// Supported tokens (initial subset):
// - identifiers: [A-Za-z_][A-Za-z0-9_]*
// - numbers: 123, 1.23, .5, 1e-3
// - punctuation: { } ( ) , : = + - * /
// - comments: ; to end of line

enum FrmTokKind {
  ident,
  number,
  lBrace,
  rBrace,
  lParen,
  rParen,
  comma,
  colon,
  eq,
  plus,
  minus,
  star,
  slash,
  newline,
  eof,
}

final class FrmTok {
  const FrmTok(this.kind, this.lexeme, this.offset);

  final FrmTokKind kind;
  final String lexeme;
  final int offset;

  @override
  String toString() => '$kind("$lexeme")@$offset';
}

final class FrmLexer {
  FrmLexer(this.src);

  final String src;
  int _i = 0;

  List<FrmTok> tokenize() {
    final out = <FrmTok>[];
    while (true) {
      final tok = _next();
      out.add(tok);
      if (tok.kind == FrmTokKind.eof) return out;
    }
  }

  FrmTok _next() {
    _skipSpaces();
    if (_i >= src.length) return FrmTok(FrmTokKind.eof, '', _i);

    final c = src.codeUnitAt(_i);

    // newline
    if (c == 0x0A) {
      _i++;
      return FrmTok(FrmTokKind.newline, '\n', _i - 1);
    }
    if (c == 0x0D) {
      // CRLF or CR
      final start = _i;
      _i++;
      if (_i < src.length && src.codeUnitAt(_i) == 0x0A) _i++;
      return FrmTok(FrmTokKind.newline, '\n', start);
    }

    // comment ;...
    if (c == 0x3B) {
      while (_i < src.length) {
        final cc = src.codeUnitAt(_i);
        if (cc == 0x0A || cc == 0x0D) break;
        _i++;
      }
      // emit newline separately in next call
      return _next();
    }

    switch (c) {
      case 0x7B: // {
        _i++;
        return FrmTok(FrmTokKind.lBrace, '{', _i - 1);
      case 0x7D: // }
        _i++;
        return FrmTok(FrmTokKind.rBrace, '}', _i - 1);
      case 0x28: // (
        _i++;
        return FrmTok(FrmTokKind.lParen, '(', _i - 1);
      case 0x29: // )
        _i++;
        return FrmTok(FrmTokKind.rParen, ')', _i - 1);
      case 0x2C: // ,
        _i++;
        return FrmTok(FrmTokKind.comma, ',', _i - 1);
      case 0x3A: // :
        _i++;
        return FrmTok(FrmTokKind.colon, ':', _i - 1);
      case 0x3D: // =
        _i++;
        return FrmTok(FrmTokKind.eq, '=', _i - 1);
      case 0x2B: // +
        _i++;
        return FrmTok(FrmTokKind.plus, '+', _i - 1);
      case 0x2D: // -
        _i++;
        return FrmTok(FrmTokKind.minus, '-', _i - 1);
      case 0x2A: // *
        _i++;
        return FrmTok(FrmTokKind.star, '*', _i - 1);
      case 0x2F: // /
        _i++;
        return FrmTok(FrmTokKind.slash, '/', _i - 1);
    }

    if (_isDigit(c) || c == 0x2E /* . */) {
      return _number();
    }

    if (_isAlpha(c) || c == 0x5F /* _ */) {
      return _ident();
    }

    throw FormatException('Unexpected character: ${String.fromCharCode(c)}', src, _i);
  }

  void _skipSpaces() {
    while (_i < src.length) {
      final c = src.codeUnitAt(_i);
      if (c == 0x20 || c == 0x09) {
        _i++;
        continue;
      }
      break;
    }
  }

  FrmTok _ident() {
    final start = _i;
    _i++;
    while (_i < src.length) {
      final c = src.codeUnitAt(_i);
      if (_isAlphaNum(c) || c == 0x5F) {
        _i++;
      } else {
        break;
      }
    }
    return FrmTok(FrmTokKind.ident, src.substring(start, _i), start);
  }

  FrmTok _number() {
    final start = _i;

    bool sawDigit = false;

    // int part or leading '.'
    if (_i < src.length && _isDigit(src.codeUnitAt(_i))) {
      sawDigit = true;
      while (_i < src.length && _isDigit(src.codeUnitAt(_i))) {
        _i++;
      }
    }

    // decimal
    if (_i < src.length && src.codeUnitAt(_i) == 0x2E /* . */) {
      _i++;
      while (_i < src.length && _isDigit(src.codeUnitAt(_i))) {
        sawDigit = true;
        _i++;
      }
    }

    if (!sawDigit) {
      throw FormatException('Invalid number', src, start);
    }

    // exponent
    if (_i < src.length) {
      final c = src.codeUnitAt(_i);
      if (c == 0x65 /* e */ || c == 0x45 /* E */) {
        _i++;
        if (_i < src.length) {
          final s = src.codeUnitAt(_i);
          if (s == 0x2B /* + */ || s == 0x2D /* - */) _i++;
        }
        final expStart = _i;
        while (_i < src.length && _isDigit(src.codeUnitAt(_i))) {
          _i++;
        }
        if (expStart == _i) {
          throw FormatException('Invalid exponent', src, expStart);
        }
      }
    }

    return FrmTok(FrmTokKind.number, src.substring(start, _i), start);
  }

  static bool _isDigit(int c) => c >= 0x30 && c <= 0x39;
  static bool _isAlpha(int c) => (c >= 0x41 && c <= 0x5A) || (c >= 0x61 && c <= 0x7A);
  static bool _isAlphaNum(int c) => _isAlpha(c) || _isDigit(c);
}

import 'frm_ast.dart';
import 'frm_lexer.dart';

/// Parser for a small Fractint-style .frm subset.
///
/// Current supported subset:
/// - Multiple formulas per file.
/// - `name { <init-stmts> : <iter-stmts> }`
/// - Stmts: `<ident> = <expr>` separated by newlines.
/// - Expr: numbers, identifiers, (re,im) complex literals, + - * / with parens.
///
/// This is intentionally small; we’ll extend it iteratively with functions,
/// power, comparisons, and bailout conditions once golden iteration tests are in.
bool isFrmStatementBoundary(FrmTokKind kind) =>
    kind == FrmTokKind.newline ||
    kind == FrmTokKind.colon ||
    kind == FrmTokKind.rBrace ||
    kind == FrmTokKind.eof;

bool isFrmFormulaBodyEnd(FrmTokKind kind) =>
    kind == FrmTokKind.rBrace || kind == FrmTokKind.eof;

final class FrmParser {
  FrmParser(String src) : _toks = FrmLexer(src).tokenize();

  final List<FrmTok> _toks;
  int _p = 0;

  FrmFile parseFile() {
    final formulas = <FrmFormula>[];
    _skipNewlines();
    while (!_peekIs(FrmTokKind.eof)) {
      formulas.add(_parseFormula());
      _skipNewlines();
    }
    return FrmFile(formulas);
  }

  FrmFormula _parseFormula() {
    final nameTok = _expect(FrmTokKind.ident, 'Expected formula name');
    _skipNewlines();
    _expect(FrmTokKind.lBrace, 'Expected "{" after formula name');

    final init = <FrmStmt>[];
    final iter = <FrmStmt>[];

    _skipNewlines();
    while (!_peekIs(FrmTokKind.colon)) {
      _expectInitSectionContinues();
      final stmt = _parseStmt();
      init.add(stmt);
      _skipNewlines();
    }

    _expect(FrmTokKind.colon, 'Expected ":" separating init/iter');
    _skipNewlines();

    while (!_peekIs(FrmTokKind.rBrace)) {
      if (_peekIs(FrmTokKind.eof)) {
        throw FormatException('Unterminated formula body', '', _peek().offset);
      }
      final stmt = _parseStmt();
      iter.add(stmt);
      _skipNewlines();
    }

    _expect(FrmTokKind.rBrace, 'Expected "}"');

    return FrmFormula(name: nameTok.lexeme, init: init, iter: iter);
  }

  FrmStmt _parseStmt() {
    final name = _expect(FrmTokKind.ident, 'Expected identifier').lexeme;
    _expect(FrmTokKind.eq, 'Expected "="');
    final expr = _parseExpr();
    _expectStmtBoundary();
    return FrmAssign(name, expr);
  }

  void _expectInitSectionContinues() {
    final tok = _peek();
    if (!isFrmFormulaBodyEnd(tok.kind)) return;
    if (tok.kind == FrmTokKind.eof) {
      throw FormatException('Unterminated formula body', '', tok.offset);
    }
    throw FormatException('Expected ":" in formula body', '', tok.offset);
  }

  void _expectStmtBoundary() {
    final tok = _peek();
    if (!isFrmStatementBoundary(tok.kind)) {
      throw FormatException('Expected newline after statement', '', tok.offset);
    }
  }

  FrmExpr _parseExpr() => _parseAddSub();

  FrmExpr _parseAddSub() {
    var expr = _parseMulDiv();
    while (true) {
      if (_match(FrmTokKind.plus)) {
        expr = FrmBinary(FrmBinaryOp.add, expr, _parseMulDiv());
        continue;
      }
      if (_match(FrmTokKind.minus)) {
        expr = FrmBinary(FrmBinaryOp.sub, expr, _parseMulDiv());
        continue;
      }
      return expr;
    }
  }

  FrmExpr _parseMulDiv() {
    var expr = _parsePrimary();
    while (true) {
      if (_match(FrmTokKind.star)) {
        expr = FrmBinary(FrmBinaryOp.mul, expr, _parsePrimary());
        continue;
      }
      if (_match(FrmTokKind.slash)) {
        expr = FrmBinary(FrmBinaryOp.div, expr, _parsePrimary());
        continue;
      }
      return expr;
    }
  }

  FrmExpr _parsePrimary() {
    if (_match(FrmTokKind.number)) {
      return FrmNumber(double.parse(_prev().lexeme));
    }

    if (_match(FrmTokKind.ident)) {
      return FrmVar(_prev().lexeme);
    }

    if (_match(FrmTokKind.lParen)) {
      // Could be (expr) or (re,im)
      final first = _parseExpr();
      if (_match(FrmTokKind.comma)) {
        final second = _parseExpr();
        _expect(FrmTokKind.rParen, 'Expected ")"');
        return FrmComplexLiteral(first, second);
      }
      _expect(FrmTokKind.rParen, 'Expected ")"');
      return first;
    }

    if (_match(FrmTokKind.minus)) {
      // unary minus: -x  => (0 - x)
      return FrmBinary(FrmBinaryOp.sub, const FrmNumber(0), _parsePrimary());
    }

    throw FormatException('Expected expression', '', _peek().offset);
  }

  void _skipNewlines() {
    while (_match(FrmTokKind.newline)) {}
  }

  bool _match(FrmTokKind kind) {
    if (_peekIs(kind)) {
      _p++;
      return true;
    }
    return false;
  }

  FrmTok _expect(FrmTokKind kind, String msg) {
    final tok = _peek();
    if (tok.kind != kind) {
      throw FormatException(msg, '', tok.offset);
    }
    _p++;
    return tok;
  }

  FrmTok _peek() => _toks[_p];
  FrmTok _prev() => _toks[_p - 1];
  bool _peekIs(FrmTokKind k) => _peek().kind == k;
}

import 'complex.dart';

sealed class FrmExpr {
  const FrmExpr();

  Complex eval(FrmEvalContext ctx);
}

final class FrmNumber extends FrmExpr {
  const FrmNumber(this.value);

  final double value;

  @override
  Complex eval(FrmEvalContext ctx) => Complex(value, 0);
}

final class FrmComplexLiteral extends FrmExpr {
  const FrmComplexLiteral(this.re, this.im);

  final FrmExpr re;
  final FrmExpr im;

  @override
  Complex eval(FrmEvalContext ctx) {
    final r = evalFrmRealScalarComponent(re, ctx, componentName: 'real');
    final i = evalFrmRealScalarComponent(im, ctx, componentName: 'imaginary');
    return Complex(r, i);
  }
}

/// Evaluates one component of a `(real, imaginary)` literal.
///
/// FRM complex literal components are scalar slots. Silently taking `.re` from
/// a complex-valued expression drops data and makes replay depend on an
/// undocumented truncation rule, so reject that shape at the evaluation seam.
double evalFrmRealScalarComponent(
  FrmExpr expr,
  FrmEvalContext ctx, {
  required String componentName,
}) {
  final value = expr.eval(ctx);
  if (value.im == 0.0) return value.re;
  throw StateError(
    'Complex literal components must evaluate to real scalars; '
    '$componentName component was $value',
  );
}

final class FrmVar extends FrmExpr {
  const FrmVar(this.name);

  final String name;

  @override
  Complex eval(FrmEvalContext ctx) =>
      ctx.vars[name] ?? (throw StateError('Unknown var: $name'));
}

enum FrmBinaryOp { add, sub, mul, div }

final class FrmBinary extends FrmExpr {
  const FrmBinary(this.op, this.left, this.right);

  final FrmBinaryOp op;
  final FrmExpr left;
  final FrmExpr right;

  @override
  Complex eval(FrmEvalContext ctx) {
    final a = left.eval(ctx);
    final b = right.eval(ctx);
    return switch (op) {
      FrmBinaryOp.add => a + b,
      FrmBinaryOp.sub => a - b,
      FrmBinaryOp.mul => a * b,
      FrmBinaryOp.div => a / b,
    };
  }
}

sealed class FrmStmt {
  const FrmStmt();

  void run(FrmEvalContext ctx);
}

final class FrmAssign extends FrmStmt {
  const FrmAssign(this.name, this.expr);

  final String name;
  final FrmExpr expr;

  @override
  void run(FrmEvalContext ctx) {
    ctx.vars[name] = expr.eval(ctx);
  }
}

/// Execution context for a single pixel / iteration.
final class FrmEvalContext {
  FrmEvalContext({required this.vars});

  final Map<String, Complex> vars;
}

final class FrmFormula {
  FrmFormula({
    required this.name,
    required Iterable<FrmStmt> init,
    required Iterable<FrmStmt> iter,
  })  : init = List.unmodifiable(init),
        iter = List.unmodifiable(iter);

  final String name;

  /// Statements before `:`
  final List<FrmStmt> init;

  /// Statements after `:`
  final List<FrmStmt> iter;
}

final class FrmFile {
  FrmFile(Iterable<FrmFormula> formulas)
      : formulas = List.unmodifiable(formulas);

  final List<FrmFormula> formulas;
}

/// Minimal complex number type for CPU-side formula evaluation.
///
/// We keep this tiny and allocation-light so we can evolve it into a proper
/// iteration engine later.
class Complex {
  const Complex(this.re, this.im);

  final double re;
  final double im;

  Complex operator +(Complex other) => Complex(re + other.re, im + other.im);
  Complex operator -(Complex other) => Complex(re - other.re, im - other.im);

  Complex operator *(Complex other) => Complex(
        re * other.re - im * other.im,
        re * other.im + im * other.re,
      );

  Complex operator /(Complex other) {
    final denom = other.re * other.re + other.im * other.im;
    return Complex(
      (re * other.re + im * other.im) / denom,
      (im * other.re - re * other.im) / denom,
    );
  }

  Complex scale(double s) => Complex(re * s, im * s);

  double abs2() => re * re + im * im;

  @override
  String toString() => '($re,$im)';
}

import 'package:equatable/equatable.dart';

/// Supported export image formats
enum ExportFormat {
  png,
  jpg,
  webp,
}

extension ExportFormatExtension on ExportFormat {
  String get extension {
    switch (this) {
      case ExportFormat.png:
        return 'png';
      case ExportFormat.jpg:
        return 'jpg';
      case ExportFormat.webp:
        return 'webp';
    }
  }

  String get mimeType {
    switch (this) {
      case ExportFormat.png:
        return 'image/png';
      case ExportFormat.jpg:
        return 'image/jpeg';
      case ExportFormat.webp:
        return 'image/webp';
    }
  }

  String get displayName {
    switch (this) {
      case ExportFormat.png:
        return 'PNG';
      case ExportFormat.jpg:
        return 'JPG';
      case ExportFormat.webp:
        return 'WebP';
    }
  }
}

/// Shared export dimension validation.
///
/// Screen dimensions and user-provided custom dimensions must resolve through
/// the same upper bound. Otherwise a typed custom size can bypass the safety
/// clamp used for invalid screen metrics and request an unreplayably huge
/// capture surface.
class ExportDimensionPolicy {
  static const int maxPixelDimension = 1 << 30;

  const ExportDimensionPolicy._();

  static int positiveRoundedScreenDimension(double value) {
    if (!value.isFinite || value <= 0) return 1;
    return value.round().clamp(1, maxPixelDimension);
  }

  static int? positiveCustomDimension(int? value) {
    if (value == null || value <= 0) return null;
    return value.clamp(1, maxPixelDimension);
  }
}

/// Preset resolution options for export
enum ExportResolution {
  screen, // Current screen resolution
  hd, // 1280x720
  fullHd, // 1920x1080
  quadHd, // 2560x1440
  uhd4k, // 3840x2160
  instagram, // 1080x1080 (square)
  instagramStory, // 1080x1920 (9:16)
  twitter, // 1200x675 (16:9)
  custom,
}

extension ExportResolutionExtension on ExportResolution {
  String get displayName {
    switch (this) {
      case ExportResolution.screen:
        return 'Screen';
      case ExportResolution.hd:
        return 'HD (1280×720)';
      case ExportResolution.fullHd:
        return 'Full HD (1920×1080)';
      case ExportResolution.quadHd:
        return '2K (2560×1440)';
      case ExportResolution.uhd4k:
        return '4K (3840×2160)';
      case ExportResolution.instagram:
        return 'Instagram (1080×1080)';
      case ExportResolution.instagramStory:
        return 'Instagram Story (1080×1920)';
      case ExportResolution.twitter:
        return 'Twitter (1200×675)';
      case ExportResolution.custom:
        return 'Custom';
    }
  }

  /// Returns (width, height) for preset resolutions
  /// Returns null for screen (use device size) or custom (user specified)
  (int, int)? get dimensions {
    switch (this) {
      case ExportResolution.screen:
        return null;
      case ExportResolution.hd:
        return (1280, 720);
      case ExportResolution.fullHd:
        return (1920, 1080);
      case ExportResolution.quadHd:
        return (2560, 1440);
      case ExportResolution.uhd4k:
        return (3840, 2160);
      case ExportResolution.instagram:
        return (1080, 1080);
      case ExportResolution.instagramStory:
        return (1080, 1920);
      case ExportResolution.twitter:
        return (1200, 675);
      case ExportResolution.custom:
        return null;
    }
  }

  bool get isSocialPreset {
    return this == ExportResolution.instagram ||
        this == ExportResolution.instagramStory ||
        this == ExportResolution.twitter;
  }
}

/// Metadata to embed in exported images
class ExportMetadata extends Equatable {
  final String? title;
  final String? description;
  final String fractalType;
  final Map<String, Object> parameters;
  final DateTime createdAt;
  final String appVersion;

  const ExportMetadata({
    this.title,
    this.description,
    required this.fractalType,
    required this.parameters,
    required this.createdAt,
    this.appVersion = '1.0.0',
  });

  Map<String, String> toExifMap() {
    return {
      'Software': 'Flutter Fractals $appVersion',
      'ImageDescription':
          description ?? 'Fractal artwork created with Flutter Fractals',
      'Artist': 'Flutter Fractals',
      'Copyright': '© ${createdAt.year} Flutter Fractals',
      'UserComment': _buildUserComment(),
    };
  }

  String _buildUserComment() {
    final buffer = StringBuffer();
    buffer.writeln('Fractal Type: $fractalType');
    buffer.writeln('Created: ${createdAt.toIso8601String()}');
    buffer.writeln('Parameters:');
    for (final entry in parameters.entries) {
      buffer.writeln('  ${entry.key}: ${entry.value}');
    }
    return buffer.toString();
  }

  @override
  List<Object?> get props =>
      [title, description, fractalType, parameters, createdAt, appVersion];
}

/// Complete export configuration
class ExportOptions extends Equatable {
  static const Object _unset = Object();

  final ExportFormat format;
  final ExportResolution resolution;
  final int? customWidth;
  final int? customHeight;
  final bool transparentBackground;
  final int quality; // 1-100, for JPG/WebP
  final bool embedMetadata;
  final ExportMetadata? metadata;
  final bool addWatermark;
  final String? watermarkText;

  const ExportOptions({
    this.format = ExportFormat.png,
    this.resolution = ExportResolution.fullHd,
    this.customWidth,
    this.customHeight,
    this.transparentBackground = false,
    this.quality = 95,
    this.embedMetadata = true,
    this.metadata,
    this.addWatermark = false,
    this.watermarkText,
  });

  static T? _nullableCopyWithValue<T>({
    required Object? candidate,
    required T? currentValue,
    required String fieldName,
  }) {
    assert(
      identical(candidate, _unset) || candidate == null || candidate is T,
      '$fieldName must be a $T? value',
    );

    return identical(candidate, _unset) ? currentValue : candidate as T?;
  }

  int _customOrScreenDimension(int? customValue, double screenValue) {
    return ExportDimensionPolicy.positiveCustomDimension(customValue) ??
        ExportDimensionPolicy.positiveRoundedScreenDimension(screenValue);
  }

  double _safeDimensionRatio(int targetDimension, double screenDimension) {
    final safeScreenDimension =
        ExportDimensionPolicy.positiveRoundedScreenDimension(screenDimension);
    return targetDimension / safeScreenDimension;
  }

  bool _preservesPresetOrientation() {
    return resolution.isSocialPreset;
  }

  (int, int)? _orientedPresetDimensions(
      double screenWidth, double screenHeight) {
    final dims = resolution.dimensions;
    if (dims == null) return null;

    final width = dims.$1;
    final height = dims.$2;
    final isPresetSquare = width == height;
    if (isPresetSquare || _preservesPresetOrientation()) return dims;

    final screenPortrait = screenHeight > screenWidth;
    final presetPortrait = height > width;

    if (screenPortrait != presetPortrait) {
      return (height, width);
    }

    return dims;
  }

  /// Calculate the pixel ratio needed to achieve target resolution
  double calculatePixelRatio(double screenWidth, double screenHeight) {
    final dims = _orientedPresetDimensions(screenWidth, screenHeight);
    if (dims != null) {
      // Use the larger ratio to ensure we meet target resolution
      final widthRatio = _safeDimensionRatio(dims.$1, screenWidth);
      final heightRatio = _safeDimensionRatio(dims.$2, screenHeight);
      // Use max to ensure we hit the target resolution on both axes
      return (widthRatio > heightRatio ? widthRatio : heightRatio)
          .clamp(1.0, 8.0);
    }

    if (resolution == ExportResolution.custom) {
      final targetWidth = _customOrScreenDimension(customWidth, screenWidth);
      final targetHeight = _customOrScreenDimension(customHeight, screenHeight);
      final widthRatio = _safeDimensionRatio(targetWidth, screenWidth);
      final heightRatio = _safeDimensionRatio(targetHeight, screenHeight);
      return (widthRatio > heightRatio ? widthRatio : heightRatio)
          .clamp(1.0, 8.0);
    }

    return 2.5; // Default for screen resolution
  }

  /// Get the target dimensions for this export
  (int, int) getTargetDimensions(double screenWidth, double screenHeight) {
    final dims = _orientedPresetDimensions(screenWidth, screenHeight);
    if (dims != null) {
      return dims;
    }

    if (resolution == ExportResolution.custom) {
      return (
        _customOrScreenDimension(customWidth, screenWidth),
        _customOrScreenDimension(customHeight, screenHeight),
      );
    }

    // Screen resolution
    return (
      ExportDimensionPolicy.positiveRoundedScreenDimension(screenWidth),
      ExportDimensionPolicy.positiveRoundedScreenDimension(screenHeight),
    );
  }

  ExportOptions copyWith({
    ExportFormat? format,
    ExportResolution? resolution,
    Object? customWidth = _unset,
    Object? customHeight = _unset,
    bool? transparentBackground,
    int? quality,
    bool? embedMetadata,
    Object? metadata = _unset,
    bool? addWatermark,
    Object? watermarkText = _unset,
  }) {
    assert(
      identical(metadata, _unset) ||
          metadata == null ||
          metadata is ExportMetadata,
      'metadata must be an ExportMetadata? value',
    );
    assert(
      identical(watermarkText, _unset) ||
          watermarkText == null ||
          watermarkText is String,
      'watermarkText must be a String? value',
    );

    return ExportOptions(
      format: format ?? this.format,
      resolution: resolution ?? this.resolution,
      customWidth: _nullableCopyWithValue<int>(
        candidate: customWidth,
        currentValue: this.customWidth,
        fieldName: 'customWidth',
      ),
      customHeight: _nullableCopyWithValue<int>(
        candidate: customHeight,
        currentValue: this.customHeight,
        fieldName: 'customHeight',
      ),
      transparentBackground:
          transparentBackground ?? this.transparentBackground,
      quality: quality ?? this.quality,
      embedMetadata: embedMetadata ?? this.embedMetadata,
      metadata: _nullableCopyWithValue<ExportMetadata>(
        candidate: metadata,
        currentValue: this.metadata,
        fieldName: 'metadata',
      ),
      addWatermark: addWatermark ?? this.addWatermark,
      watermarkText: _nullableCopyWithValue<String>(
        candidate: watermarkText,
        currentValue: this.watermarkText,
        fieldName: 'watermarkText',
      ),
    );
  }

  @override
  List<Object?> get props => [
        format,
        resolution,
        customWidth,
        customHeight,
        transparentBackground,
        quality,
        embedMetadata,
        metadata,
        addWatermark,
        watermarkText,
      ];
}

